-- =====================================================================
-- بيانات تجريبية (Seed) لتعبئة قاعدة البيانات بمحتوى يظهر في الموقع
-- 5 فئات / 6 موردين / 12 منتج / ~40 عرض بأسعار مختلفة
-- آمن لإعادة التشغيل (idempotent).
-- icon = أسماء أيقونات lucide-react (مع fallback إلى Package في الواجهة).
-- =====================================================================

-- ---------- الفئات ----------
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, icon = EXCLUDED.icon;

-- ---------- الموردون ----------
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, city = EXCLUDED.city, phone = EXCLUDED.phone, whatsapp = EXCLUDED.whatsapp,
  rating = EXCLUDED.rating, reviews_count = EXCLUDED.reviews_count, verified = EXCLUDED.verified,
  joined_year = EXCLUDED.joined_year;

-- ---------- المنتجات ----------
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, category_id = EXCLUDED.category_id, icon = EXCLUDED.icon,
  unit = EXCLUDED.unit, spec = EXCLUDED.spec;

-- ---------- العروض ----------
DELETE FROM public.offers WHERE product_id IN (
  '0a000000-0000-4000-8000-000000000001','0a000000-0000-4000-8000-000000000002',
  '0a000000-0000-4000-8000-000000000003','0a000000-0000-4000-8000-000000000004',
  '0a000000-0000-4000-8000-000000000005','0a000000-0000-4000-8000-000000000006',
  '0a000000-0000-4000-8000-000000000007','0a000000-0000-4000-8000-000000000008',
  '0a000000-0000-4000-8000-000000000009','0a000000-0000-4000-8000-000000000010',
  '0a000000-0000-4000-8000-000000000011','0a000000-0000-4000-8000-000000000012'
);

